   139|// Provider auto-detection: the key prefix determines the correct endpoint.
   140|//   vck_  → Vercel AI Gateway (https://ai-gateway.vercel.sh/v1)
   141|//   sk-   → OpenAI direct API (https://api.openai.com/v1)
   142|// This makes the runtime self-healing: whichever key is loaded on the host,
   143|// it is routed to the matching provider. A vck_ key sent to api.openai.com
   144|// fails with 401 invalid_api_key; an sk- key sent to ai-gateway.vercel.sh
   145|// fails with 401. Auto-detection eliminates both failure modes.
   146|const VERCEL_AI_GATEWAY_BASE = 'https://ai-gateway.vercel.sh/v1';
   147|const OPENAI_DIRECT_BASE = 'https://api.openai.com/v1';
   148|
   149|function isVercelGatewayKey(key: string): boolean {
   150|  return key.startsWith('vck_');
   151|}
   152|
   153|function isOpenAIDirectKey(key: string): boolean {
   154|  return key.startsWith('sk-');
   155|}
   156|
   157|function getIVXAIGatewayApiKey(): string {
   158|  return readTrimmed(process.env.OPENAI_API_KEY) || readTrimmed(process.env.AI_GATEWAY_API_KEY);
