   161|/**
   162| * Returns the AI provider type based on the loaded API key prefix.
   163| * 'vercel_gateway'  → vck_ key, routes to ai-gateway.vercel.sh/v1
   164| * 'openai_direct'   → sk- key, routes to api.openai.com/v1
   165| * 'unknown'         → key not loaded or unrecognized prefix
   166| */
   167|export function getIVXAIProviderType(): 'vercel_gateway' | 'openai_direct' | 'unknown' {
   168|  const key = getIVXAIGatewayApiKey();
   169|  if (!key) return 'unknown';
   170|  if (isVercelGatewayKey(key)) return 'vercel_gateway';
   171|  if (isOpenAIDirectKey(key)) return 'openai_direct';
   172|  return 'unknown';
   173|}
