   175|/**
   176| * Returns the base URL for the AI provider, auto-detected from the key prefix.
   177| * If IVX_AI_GATEWAY_URL is explicitly set (and not a Rork domain), it takes
   178| * priority — this lets the operator override the auto-detection if needed.
   179| * Otherwise, the key prefix determines the endpoint.
   180| */
   181|function getIVXAIGatewayRootUrl(): string {
   182|  const configured = readTrimmed(process.env.IVX_AI_GATEWAY_URL);
   183|  // Rork independence guard: never honor a gateway URL that points at a
   184|  // Rork-hosted domain, even if a stale env var is still set on the host.
   185|  if (configured && !isRorkDomain(configured)) {
   186|    return configured;
   187|  }
   188|  // Auto-detect from key prefix
   189|  const key = getIVXAIGatewayApiKey();
   190|  if (key && isVercelGatewayKey(key)) {
   191|    return VERCEL_AI_GATEWAY_BASE;
   192|  }
   193|  return OPENAI_DIRECT_BASE;
   194|}
   195|
   196|function buildGatewayBaseUrl(rootUrl: string): string | null {
   197|  const trimmed = readTrimmed(rootUrl).replace(/\/+$/, '');
   198|  return trimmed || null;
   199|}
   200|
   201|function getGatewayBaseUrl(): string | null {
   202|  return buildGatewayBaseUrl(getIVXAIGatewayRootUrl());
   203|}
   204|
   205|function isRorkDomain(url: string): boolean {
   206|  const lower = url.toLowerCase();
   207|  return lower.includes('toolkit.rork.com')
   208|    || lower.includes('api.rork.com')
   209|    || lower.endsWith('.rork.com')
   210|    || lower.includes('rork-direct.workers.dev');
   211|}
   212|
   213|function getGatewayBaseUrlCandidates(): string[] {
   214|  const configured = getGatewayBaseUrl();
   215|  // Auto-detect fallback candidate based on key prefix.
   216|  // If the primary is a Vercel key (vck_), the fallback candidate is OpenAI direct.
   217|  // If the primary is an OpenAI key (sk-), the fallback candidate is the Vercel gateway.
   218|  // This ensures both endpoints are tried if the key/URL auto-detection mismatches.
   219|  const key = getIVXAIGatewayApiKey();
   220|  const fallbackCandidate = key && isVercelGatewayKey(key)
   221|    ? buildGatewayBaseUrl(OPENAI_DIRECT_BASE)
   222|    : buildGatewayBaseUrl(VERCEL_AI_GATEWAY_BASE);
   223|  // Rork independence guard: any candidate that resolves to a Rork domain is
   224|  // filtered out, so a stale env var cannot re-route through toolkit.rork.com.
   225|  const candidates = [configured, fallbackCandidate].filter((c): c is string => c !== null && !isRorkDomain(c));
   226|  return [...new Set(candidates)];
   227|}
   228|
   229|function ensureIVXAIGatewayEnvironment(): void {
   230|  const apiKey = getIVXAIGatewayApiKey();
   231|  if (!apiKey) {
   232|    throw new Error(
   233|      'IVX AI runtime is not configured. Set OPENAI_API_KEY on the backend host.',
   234|    );
   235|  }
   236|  // Bridge OPENAI_API_KEY → AI_GATEWAY_API_KEY so createGateway() can find the
   237|  // key via its expected env var. Without this, createGateway sends no auth
   238|  // header and the Vercel AI Gateway returns "Unauthenticated. Configure
   239|  // AI_GATEWAY_API_KEY" even though the key is present in OPENAI_API_KEY.
   240|  if (isVercelGatewayKey(apiKey) && !process.env.AI_GATEWAY_API_KEY) {
   241|    process.env.AI_GATEWAY_API_KEY = apiKey;
   242|  }
   243|}
