   245|
   246|function readRecord(value: unknown): Record<string, unknown> {
   247|  return typeof value === 'object' && value !== null ? value as Record<string, unknown> : {};
   248|}
   249|
   250|function extractGatewayFailureContext(error: unknown): { status: number | null; responseBody: unknown } {
   251|  const record = readRecord(error);
   252|  const response = readRecord(record.response);
   253|  const cause = readRecord(record.cause);
   254|  const status = typeof record.statusCode === 'number'
   255|    ? record.statusCode
   256|    : typeof record.status === 'number'
   257|      ? record.status
   258|      : typeof record.responseStatus === 'number'
   259|        ? record.responseStatus
   260|        : typeof response.status === 'number'
   261|          ? response.status
   262|          : typeof cause.status === 'number'
   263|            ? cause.status
   264|            : null;
   265|  const responseBody = record.responseBody
   266|    ?? response.body
   267|    ?? response.data
   268|    ?? record.data
   269|    ?? record.body
   270|    ?? cause.responseBody
   271|    ?? cause.body
   272|    ?? null;
   273|  return { status, responseBody };
   274|}
   275|
   276|function normalizeGatewayFailure(error: unknown, context: IVXAIGatewayFailureContext): Error {
   277|  const traceId = context.traceId ?? generateTraceId();
   278|  const message = error instanceof Error ? error.message : 'Gateway request failed';
   279|  const body = typeof context.responseBody === 'string'
   280|    ? context.responseBody.slice(0, 600)
   281|    : context.responseBody && typeof context.responseBody === 'object'
   282|      ? JSON.stringify(context.responseBody).slice(0, 600)
   283|      : null;
   284|  const detail = [
   285|    `IVX AI gateway request failed for ${context.module}.`,
   286|    `traceId=${traceId}`,
   287|    `endpoint=${context.endpoint ?? 'unresolved'}`,
   288|    `model=${context.model}`,
   289|    context.status ? `status=${context.status}` : null,
   290|    `providerError=${message}`,
   291|    body ? `responseBody=${body}` : null,
   292|  ].filter(Boolean).join(' ');
   293|  const normalized = new Error(detail);
   294|  normalized.name = 'IVXAIGatewayRequestError';
   295|  // Attach traceId on the error object so callers can surface it to the user.
   296|  Object.defineProperty(normalized, 'traceId', { value: traceId, enumerable: false });
   297|  return normalized;
   298|}
