   300|function normalizeMessages(messages: IVXAITextMessage[] | undefined): IVXAITextMessage[] {
   301|  return (messages ?? [])
   302|    .map((message) => ({
   303|      role: message.role === 'assistant' ? 'assistant' as const : 'user' as const,
   304|      content: readTrimmed(message.content),
   305|    }))
   306|    .filter((message) => message.content.length > 0);
