   309|export function resolveIVXAIModel(explicitModel?: string | null, envCandidates: string[] = []): string {
   310|  const explicit = readTrimmed(explicitModel);
   311|  if (explicit) {
   312|    return normalizeModelForProvider(stripOpenaiPrefix(explicit));
   313|  }
   314|
   315|  for (const envName of envCandidates) {
   316|    const candidate = readTrimmed(process.env[envName]);
   317|    if (candidate) {
   318|      return normalizeModelForProvider(stripOpenaiPrefix(candidate));
   319|    }
   320|  }
   321|
   322|  return normalizeModelForProvider(DEFAULT_IVX_AI_MODEL);
   323|}
   324|
   325|/**
   326| * Normalize the model name for the active provider.
   327| * Vercel AI Gateway requires the `openai/` prefix (e.g. `openai/gpt-4o`).
   328| * OpenAI direct API uses bare model names (e.g. `gpt-4o`).
   329| */
   330|function normalizeModelForProvider(model: string): string {
   331|  const providerType = getIVXAIProviderType();
   332|  const bare = model.replace(/^openai\//, '');
   333|  if (providerType === 'vercel_gateway') {
   334|    return bare.startsWith('openai/') ? bare : `openai/${bare}`;
   335|  }
   336|  return bare;
   337|}
   338|
   339|/** Strip the openai/ prefix used by the old Vercel AI Gateway routing. */
   340|function stripOpenaiPrefix(model: string): string {
   341|  return model.replace(/^openai\//, '');
   342|}
   343|
   344|/**
   345| * Returns the API base URL (e.g. https://api.openai.com/v1). The model name is
   346| * NOT embedded in the endpoint path — the @ai-sdk/openai provider handles
   347| * model-to-route routing internally (chat/completions or responses). Embedding
   348| * the model name produced invalid URLs like https://api.openai.com/v1/gpt-4o.
   349| */
   350|export function getIVXAIEndpoint(model: string = DEFAULT_IVX_AI_MODEL): string | null {
   351|  void model; // model is NOT part of the endpoint URL
   352|  return getGatewayBaseUrl();
   353|}
   354|
   355|/**
   356| * Startup validation — verifies the AI provider/model configuration is sound.
   357| * Exposes only safe metadata (never the key value). Called at boot so
   358| * misconfigurations surface immediately instead of on the first request.
   359| */
   360|export type IVXAIStartupValidation = {
   361|  ok: boolean;
   362|  provider: string;
   363|  providerType: 'vercel_gateway' | 'openai_direct' | 'unknown';
   364|  model: string;
   365|  adapterVersion: string;
   366|  keyLoaded: boolean;
   367|  keyPrefix: string;
   368|  baseUrl: string | null;
   369|  endpoint: string | null;
   370|  errors: string[];
   371|};
   372|
   373|let cachedAdapterVersion: string | null = null;
   374|function getAdapterVersion(): string {
   375|  if (cachedAdapterVersion) return cachedAdapterVersion;
   376|  try {
   377|    // eslint-disable-next-line @typescript-eslint/no-require-imports
   378|    const pkg = require('@ai-sdk/openai/package.json');
   379|    cachedAdapterVersion = typeof pkg?.version === 'string' ? pkg.version : 'unknown';
   380|  } catch {
   381|    cachedAdapterVersion = 'unknown';
   382|  }
   383|  return cachedAdapterVersion!;
   384|}
   385|
   386|export function validateIVXAIStartup(): IVXAIStartupValidation {
   387|  const errors: string[] = [];
   388|  const model = normalizeModelForProvider(DEFAULT_IVX_AI_MODEL);
   389|  const rootUrl = getIVXAIGatewayRootUrl();
   390|  const apiKey = getIVXAIGatewayApiKey();
   391|  const keyLoaded = apiKey.length > 0;
   392|  const keyPrefix = keyLoaded ? `${apiKey.slice(0, 4)}***` : 'none';
   393|  const providerType = getIVXAIProviderType();
   394|  const baseUrl = getGatewayBaseUrl();
   395|  const adapterVersion = getAdapterVersion();
   396|
   397|  if (!keyLoaded) {
   398|    errors.push('OPENAI_API_KEY is not set');
   399|  }
   400|  if (!rootUrl) {
   401|    errors.push('AI gateway root URL is empty');
   402|  }
   403|  if (rootUrl && isRorkDomain(rootUrl)) {
   404|    errors.push('AI gateway URL points to a blocked Rork domain');
   405|  }
   406|  // Verify the adapter is spec v3 compatible (v4 is rejected by ai@6)
   407|  const majorVersion = Number.parseInt(adapterVersion.split('.')[0] ?? '0', 10);
   408|  if (majorVersion > 3) {
   409|    errors.push(`@ai-sdk/openai@${adapterVersion} uses spec v4, incompatible with ai@6 — downgrade to @ai-sdk/openai@3.x`);
   410|  }
   411|  // Warn if key prefix doesn't match any known provider
   412|  if (keyLoaded && providerType === 'unknown') {
   413|    errors.push(`API key prefix ${keyPrefix} is not recognized (expected sk- for OpenAI or vck_ for Vercel AI Gateway)`);
   414|  }
   415|
   416|  return {
   417|    ok: errors.length === 0,
   418|    provider: providerType === 'vercel_gateway' ? 'vercel_ai_gateway' : 'openai',
   419|    providerType,
   420|    model,
   421|    adapterVersion,
   422|    keyLoaded,
   423|    keyPrefix,
   424|    baseUrl,
   425|    endpoint: getIVXAIEndpoint(model),
   426|    errors,
   427|  };
   428|}
   429|
   430|/** Generate a short trace ID for request correlation. */
   431|export function generateTraceId(): string {
   432|  return `ivx-trace-${randomUUID().split('-')[0]}`;
   433|}
   434|
   435|export function isIVXAIConfigured(): boolean {
   436|  return getIVXAIGatewayRootUrl().length > 0 && getIVXAIGatewayApiKey().length > 0;
   437|}
   438|
   439|export function getIVXAIConfigurationSnapshot(model: string = DEFAULT_IVX_AI_MODEL): IVXAIConfigurationSnapshot {
   440|  const hasGatewayUrl = getIVXAIGatewayRootUrl().length > 0;
   441|  const hasGatewayApiKey = getIVXAIGatewayApiKey().length > 0;
   442|  return {
   443|    configured: hasGatewayUrl && hasGatewayApiKey,
   444|    hasGatewayUrl,
   445|    hasGatewayApiKey,
   446|    model,
   447|    endpoint: getIVXAIEndpoint(model),
   448|    runtime: 'ivx_ai_gateway',
   449|    layer: 'ivx_ai_runtime_wrapper',
   450|    phase: 'agent_runtime_v2',
   451|  };
   452|}
   453|
   454|export async function requestIVXAIText(input: {
   455|  module: IVXAIModule;
   456|  requestId?: string | null;
   457|  model?: string | null;
   458|  system?: string | null;
   459|  prompt?: string | null;
   460|  messages?: IVXAITextMessage[];
   461|  images?: IVXAIImageAttachment[];
   462|  files?: IVXAIFileAttachment[];
   463|  maxOutputTokens?: number;
   464|}): Promise<IVXAITextResult> {
   465|  const model = resolveIVXAIModel(input.model);
   466|  const endpoint = getIVXAIEndpoint(model);
   467|  const messages = normalizeMessages(input.messages);
   468|  const prompt = readTrimmed(input.prompt);
   469|  const system = readTrimmed(input.system);
   470|  const images = (input.images ?? [])
   471|    .map((img) => ({ url: readTrimmed(img.url), mimeType: readTrimmed(img.mimeType ?? '') || null }))
   472|    .filter((img) => img.url.length > 0);
   473|  const files = (input.files ?? []).filter(
   474|    (file) => readTrimmed(file.mediaType).length > 0 && file.data != null,
   475|  );
   476|
   477|  if (!prompt && messages.length === 0) {
   478|    throw new Error('IVX AI request requires a prompt or messages.');
   479|  }
   480|
   481|  const baseUrlCandidates = getGatewayBaseUrlCandidates();
   482|  if (baseUrlCandidates.length === 0) {
   483|    throw new Error('IVX AI runtime is not configured.');
   484|  }
   485|
   486|  console.log('[IVXAI] Routing request through IVX AI Phase 1 wrapper:', {
   487|    module: input.module,
   488|    requestId: input.requestId ?? null,
   489|    model,
   490|    endpoint,
   491|    baseUrlCandidates,
   492|    hasSystem: system.length > 0,
   493|    promptLength: prompt.length,
   494|    messageCount: messages.length,
   495|    authKeySource: 'OPENAI_API_KEY',
   496|    requestShape: messages.length > 0 ? 'messages' : 'prompt',
   497|    maxOutputTokens: input.maxOutputTokens ?? null,
   498|    phase: 'agent_runtime_v2',
   499|    layer: 'ivx_ai_runtime_wrapper',
   500|  });
   501|
   502|  // Adaptive timeout + queue gating: long prompts/reports get more time and a
   503|  // dedicated lane so they cannot block normal chat under contention.
   504|  const promptChars = prompt.length + system.length + messages.reduce((sum, m) => sum + m.content.length, 0);
   505|  const adaptiveTimeoutMs = computeAdaptiveTimeoutMs({ promptChars, maxOutputTokens: input.maxOutputTokens });
   506|  const queueLane: IVXAIQueueLane = classifyRequestLane({ promptChars, maxOutputTokens: input.maxOutputTokens });
   507|  const queueSlot = await acquireAIQueueSlot(queueLane);
   508|  const callStartedAt = Date.now();
   509|
   510|  let result: Awaited<ReturnType<typeof generateText>> | null = null;
   511|  let lastError: unknown = null;
   512|  let lastFailure: { status: number | null; responseBody: unknown } = { status: null, responseBody: null };
   513|  let successfulBaseUrl = baseUrlCandidates[0];
   514|  let retryCount = 0;
   515|
   516|  for (const baseURL of baseUrlCandidates) {
   517|    ensureIVXAIGatewayEnvironment();
   518|    try {
   519|      // Use the correct adapter for the key type:
   520|      //   vck_ key → createGateway (Vercel AI Gateway, sends auth header correctly)
   521|      //   sk-  key → createOpenAI (OpenAI direct API)
   522|      // Sending a vck_ key via createOpenAI produces 401 invalid_api_key even
   523|      // when the baseURL is ai-gateway.vercel.sh — the auth header format differs.
