    94|  if (name === 'IVXAIGatewayTimeoutError' || message.includes('timed out') || message.includes('etimedout')) {
    95|    return 'timeout';
    96|  }
    97|  if (status === 401 || status === 403 || message.includes('unauthor') || message.includes('forbidden')) {
    98|    return 'auth';
    99|  }
